#include <iostream>
#include <vector>
#include <cmath>

using namespace std;

int main()
{
    int n;
    cin >> n;
    vector<pair<int, int>> bishops;
    for (int i = 0; i < n; i++)
    {
        int x, y;
        cin >> x >> y;
        bishops.push_back(make_pair(x, y));
    }
    int count = 0;
    for (int i = 0; i < n; i++)
    {
        for (int j = i + 1; j < n; j++)
        {
            int dx = abs(bishops[i].first - bishops[j].first);
            int dy = abs(bishops[i].second - bishops[j].second);
            if (dx == dy)
            {
                count++;
            }
        }
    }
    cout << count << endl;
    return 0;
}
